INSERT INTO "categories" ("id","name","slug","description","image","parentId","order","isActive","createdAt","updatedAt","showOnHome") VALUES
('cmpjyh9bb00651dk2efqxv3hs','Kooperatif Keven Kekik Serisi','kooperatif-keven-kekik-serisi','Kooperatifimizin çatısı altında birleşen arıcılarımızın, el değmemiş keven ve kekik meralarından sağdığı lezzet. Kooperatif Keven Kekik Serisi, coğrafyamızın geniş bitki çeşitliliğini ve doğanın zarifliğini, siz değerli tüketicilerimize sunuyoruz.','/images/categories/f2685fe6-fc12-4ffb-88f9-31569a540513.webp',NULL,0,true,'2026-05-24 15:52:18.024','2026-05-30 13:36:03.797',true),
('cmpjyhza300661dk2ye2m69yu','Kooperatif Çiçek Serisi','kooperatif-cicek-serisi','Kooperatifimizin çatısı altında birleşen arıcılarımızın, el değmemiş çiçek meralarından sağdığı lezzet. Kooperatif Çiçek Serisi, coğrafyamızın geniş bitki çeşitliliğini ve doğanın zarifliğini, siz değerli tüketicilerimize sunuyoruz.','/images/categories/88d25299-cc1e-4aae-81b4-1334fa2662c7.webp',NULL,0,true,'2026-05-24 15:52:51.675','2026-05-30 13:36:03.797',true),
('cmpjyjeq400671dk25utyx9xv','Kooperatif Çam Serisi','kooperatif-cam-serisi','Kooperatifimizin çatısı altında birleşen arıcılarımızın, el değmemiş çam ormanlarından sağdığı lezzet. Kooperatif Çam Balı Serisi, coğrafyamızın geniş orman dokusunu ve doğanın zarifliğini, siz değerli tüketicilerimize sunuyoruz.','/images/categories/4dbef521-541f-44dc-a135-2ab5d5dae0be.webp',NULL,0,true,'2026-05-24 15:53:58.348','2026-05-30 13:36:03.797',true),
('cmpjykvtu00681dk234gzde37','Kooperatif Narenciye Serisi','kooperatif-narenciye-serisi','Kooperatifimizin çatısı altında birleşen arıcılarımızın, mis kokulu narenciye bahçelerinden sağdığı lezzet. Kooperatif Narenciye Balı Serisi, coğrafyamızın Akdeniz güneşiyle olgunlaşan bitki çeşitliliğini ve doğanın zarifliğini, siz değerli tüketicilerimize sunuyoruz.','/images/categories/b31e98c4-b2c6-4526-a4a0-54c164175f6e.webp',NULL,0,true,'2026-05-24 15:55:07.170','2026-05-30 13:36:03.797',true),
('cmpjym41v00691dk2b34uaad5','Kooperatif Monofloral Serisi','kooperatif-monofloral-serisi','Kooperatifimizin çatısı altında birleşen arıcılarımızın, tek bir bitki türünün hakim olduğu özel floradan sağdığı lezzet. Kooperatif Monofloral Balı Serisi, coğrafyamızın tek bir çiçeğe özgü zenginliğini ve doğanın zarifliğini, siz değerli tüketicilerimize sunuyoruz.','/images/categories/0ccdacb2-b7a7-4c08-8674-be257a1d9eac.webp',NULL,0,true,'2026-05-24 15:56:04.484','2026-05-30 13:36:03.797',true),
('cmpjyntvv006a1dk2s6vztod1','Kooperatif Avantajlı Ürünler Serisi','kooperatif-avantajli-urunler-serisi','Kooperatifimizin çatısı altında birleşen arıcılarımızın, el değmemiş coğrafyalardan sağdığı lezzet. Kooperatif Avantajlı Ürünler Serisi, doğanın zarifliğini ve kooperatif tecrübesini, sofralarınıza daha erişilebilir seçeneklerle, siz değerli tüketicilerimize sunuyoruz.','/images/categories/493e1337-a6f8-4a6d-8b89-e4ab6c412b81.webp',NULL,0,true,'2026-05-24 15:57:24.620','2026-05-30 13:36:03.797',true),
('cmpjzvo0n000655l4oohuojwm','Kooperatif Rafadan Tayfa Serisi','kooperatif-rafadan-tayfa-serisi','Kooperatifimizin çatısı altında birleşen arıcılarımızın, el değmemiş yaylalardan sağdığı lezzet. Kooperatif Rafadan Tayfa Çiçek Balı Serisi, coğrafyamızın renkli bitki çeşitliliğini ve doğanın zarifliğini, büyüme çağındaki nesillerimize ve siz değerli tüketicilerimize sunuyoruz.','/images/categories/f74cd631-169d-4e8b-a153-0b047ebfa21c.webp',NULL,0,true,'2026-05-24 16:31:29.879','2026-05-30 13:36:03.797',true),
('cmpjzzxe4000c55l4wnq7wrgy','Kooperatif Özel Ürün Serisi','kooperatif-ozel-urun-serisi','Kooperatifimizin çatısı altında birleşen arıcılarımızın, el değmemiş kovanlardan sağdığı lezzet. Kooperatif Özel Ürün Serisi; arı sütü, polen ve sıvı propolisin uyumunu, coğrafyamızın kıymetli arı mucizelerini ve doğanın zarifliğini, siz değerli tüketicilerimize sunuyoruz.','/images/categories/24c7e0ef-2aea-402d-8775-570aae8b8399.webp',NULL,0,true,'2026-05-24 16:34:48.653','2026-05-30 13:36:03.797',true),
('cmplel1wj0000541e6tlq03lu','İlk Kez Alacaklar Serisi','ilk-kez-alacaklar-serisi','Kooperatifimizin çatısı altında birleşen arıcılarımızın, el değmemiş coğrafyalardan sağdığı lezzet. Kooperatif İlk Kez Alacaklar Serisi, markamızla yeni tanışacak tüketicilerimiz için coğrafyamızın sevilen bitki çeşitliliğini ve doğanın zarifliğini, güzel bir başlangıçla siz değerli tüketicilerimize sunuyoruz.','/images/categories/e8d14f1f-514a-4d5e-b236-f65f583a1152.webp',NULL,0,true,'2026-05-25 16:10:55.075','2026-05-30 13:36:03.797',true);
