INSERT INTO "blog_posts" ("id","title","slug","excerpt","content","coverImage","authorId","isPublished","publishedAt","metaTitle","metaDescription","createdAt","updatedAt") VALUES
('cmpji1gv0000k4095yynffbiq','Gerçek Bal Nasıl Anlaşılır?','gercek-bal-nasil-anlasilir','1973 yılında, Adana''nın Kozan ilçesinde birkaç arıcı aile bir karar verdi. Tek başına ayakta kalmanın zor olduğunu biliyorlardı. Çünkü bal sadece doğanın değil, sabrın da işiydi.','<h2>Gerçek Bal Nasıl Anlaşılır?</h2>\n<p>1973 yılında, Adana''nın Kozan ilçesinde birkaç arıcı aile bir karar verdi. Tek başına ayakta kalmanın zor olduğunu biliyorlardı. Çünkü bal sadece doğanın değil, sabrın da işiydi. Yağmurun erken yağması, kuraklığın uzaması, piyasanın dengesizliği... Hepsi küçük üreticinin omzuna yük oluyordu.</p>\n<p>İşte o gün, yükü paylaşmak için bir araya geldiler. 745 Sayılı Kozan Bal Tarım Satış Kooperatifi böyle doğdu.</p>','/images/blog/265e0925-3351-46cc-8faa-f31ba904e095.webp',NULL,true,'2026-05-24 08:12:07.451','','','2026-05-24 08:12:07.452','2026-05-30 12:55:27.099'),
('cmpsce0ha0000ae4enon5bpyn','Çocuklar İçin Bal','cocuklar-icin-bal','1973 yılında, Adana''nın Kozan ilçesinde birkaç arıcı aile bal üretimi yapıyordu. Tek başına ayakta kalmak zor olduğunu biliyorlardı. Çünkü bal sadece doğanın değil, sabrın da ürünü.','<p>Çocukların sağlıklı beslenmesi için doğal bal vazgeçilmez bir besin kaynağıdır. Ancak bal, 1 yaşından küçük bebeklere kesinlikle verilmemelidir. 1 yaş üzeri çocuklar için ise doğal ve analizi yapılmış bal, bağışıklık sistemini güçlendirir, enerji sağlar ve doğal şeker alternatifi olarak günlük beslenmede yer alabilir.</p><p>Kooperatif güvencesiyle üretilen ballarımız, akredite laboratuvarlarda analiz edilmektedir.</p>','/images/blog/7c89c7f1-65e6-4134-ab88-215c574ca05e.webp',NULL,true,'2024-03-15 00:00:00.000','Çocuklar İçin Bal | Binboğa Bal Rehberi','Çocuklar için bal tüketiminde nelere dikkat edilmeli?','2026-05-30 12:43:50.638','2026-05-30 12:45:30.428'),
('cmpsce0ha0001ae4e8vlhe99g','Balın Faydaları Nelerdir?','balin-faydalari-nelerdir','Bal, binlerce yıldır hem besin hem de şifa kaynağı olarak kullanılmaktadır. Doğal antioksidanlar, mineraller ve enzimler bakımından zengin olan bal; bağışıklık sistemini güçlendirir, enerji verir.','<p>Bal, doğanın insanlara sunduğu en kıymetli armağanlardan biridir. C vitamini, B vitaminleri, kalsiyum, demir, magnezyum ve potasyum gibi değerli mineraller içerir.</p><p>Düzenli tüketildiğinde bağışıklık sistemini güçlendirir, boğaz ağrılarını hafifletir ve sindirim sistemini düzenler.</p>','/images/blog/ec6000ad-e664-47c9-9a2a-dba102f692d0.webp',NULL,true,'2024-04-01 00:00:00.000','Balın Faydaları Nelerdir? | Binboğa Bal Rehberi','Balın sağlığa faydaları nelerdir?','2026-05-30 12:43:50.638','2026-05-30 12:46:11.895'),
('cmpsce0ha0002ae4eizud7zol','Mevsime Göre Bal Seçimi','mevsime-gore-bal-secimi','Her mevsim farklı bir bal türü öne çıkar. İlkbaharda çiçek balları, yazın ıhlamur ve kestane, sonbaharda ise kovan balları en yoğun aromasına ulaşır.','<p>Doğa, her mevsimde farklı çiçekler açar; arılar da bu çiçeklerden farklı tatlar taşıyan ballar üretir. İlkbaharda açan çiçek balları hafif ve aromatiktir. Yaz aylarında toplanan ıhlamur balı rahatlatıcı etkisiyle öne çıkar. Sonbahar hasatı ise kestane balının güçlü aromasını sunar.</p>','/images/blog/f6d5448d-dcaf-4bee-9cf0-411cfcaa2c4a.png',NULL,true,'2024-05-10 00:00:00.000','Mevsime Göre Bal Seçimi | Binboğa Bal Rehberi','Hangi mevsimde hangi bal tüketilmeli?','2026-05-30 12:43:50.638','2026-05-30 13:18:19.031'),
('cmpsce0ha0003ae4exka7fzka','Bal Nasıl Saklanır?','bal-nasil-saklanir','Doğal bal, doğru saklandığında yıllarca bozulmaz. Işık, nem ve sıcaktan uzak tutmak balın ömrünü uzatır. Kristalleşme ise bozulma değil, saflığın işaretidir.','<p>Gerçek doğal bal kristalleşebilir — bu bozulma değil, saflığın işaretidir. Kristalleşen balı ılık suda bekletmek yeterlidir; kesinlikle kaynatmayın. Bal için ideal saklama sıcaklığı 10-20°C arasıdır.</p><p>Cam kavanoz tercih edin. Bala su girmesini önleyin; kaşık her zaman kuru olmalıdır.</p>','/images/blog/358e68b6-9a4a-4483-9fac-e2e45238b6bd.jpg',NULL,true,'2024-06-01 00:00:00.000','Bal Nasıl Saklanır? | Binboğa Bal Rehberi','Balı doğru saklamanın püf noktaları.','2026-05-30 12:43:50.638','2026-05-30 12:47:46.800');
INSERT INTO "faqs" ("id","question","answer","order","isActive","createdAt") VALUES
('faq-1','Kooperatif nedir?','Kooperatif, ortak ekonomik, sosyal ve kültürel çıkarlarını gerçekleştirmek amacıyla gönüllü olarak bir araya gelen kişilerin oluşturduğu, demokratik olarak kontrol edilen bir ortaklık işletmesidir.',1,true,'2026-05-24 08:12:07.420'),
('faq-2','Ürünlerimiz katkısız mı?','Evet. Tüm ürünlerimiz akredite laboratuvarlarda analiz edilmekte ve herhangi bir katkı maddesi içermediği güvence altına alınmaktadır.',2,true,'2026-05-24 08:12:07.427'),
('faq-3','Teslimat süreniz?','Siparişleriniz genellikle 1-3 iş günü içinde kargoya verilmektedir. Kargo süreci taşıyıcı firmaya göre değişmekle birlikte ortalama 2-5 iş günüdür.',3,true,'2026-05-24 08:12:07.432'),
('faq-4','Ürünlerimize katkı var mı?','Hayır. Kooperatif Balı Binboğa ürünleri tamamen doğal olup herhangi bir katkı maddesi, şeker veya yapay tatlandırıcı içermemektedir.',4,true,'2026-05-24 08:12:07.437'),
('faq-5','Ürünleriniz bal mumu?','Evet, arı mumu ürünlerimiz de mevcuttur. Ürün kategorilerimizden inceleyebilirsiniz.',5,true,'2026-05-24 08:12:07.442'),
('faq-6','Glütenimiz aktörimiz?','Ürünlerimiz doğal bal olup glüten içermemektedir. Ancak üretim tesisimizde farklı ürünler de işlenmektedir. Ciddi alerjisi olan müşterilerimizin bizi araması önerilir.',6,true,'2026-05-24 08:12:07.447');
