INSERT INTO "reviews" ("id","productId","userId","rating","comment","isApproved","createdAt","adminReply","images","orderId","orderItemId","title","updatedAt") VALUES
('cmps8aosr000897x563nchjyz','cmpjybtj7003d1dk272xxxvos','cmps8aos3000097x5hjmnoycw',5,'Gerçekten doğal bir bal. Tadı ve kıvamı mükemmel, marketten aldıklarımızla kıyaslanamaz. Her sabah kahvaltıda kullanıyoruz, aile olarak çok beğendik.',true,'2025-12-14 10:49:17.064',NULL,NULL,NULL,NULL,NULL,'2026-05-30 17:16:24.958'),
('cmps8aosv000a97x5r9ghkoul','cmpjybtj7003d1dk272xxxvos','cmps8aos5000397x5xmjxlug8',5,'Kooperatiften alınan balın farkı belli oluyor. İçinden çıktığında kokusu bile bambaşka. Kesinlikle tavsiye ederim, ikinci siparişimi de verdim.',true,'2026-02-19 10:49:17.070',NULL,NULL,NULL,NULL,NULL,'2026-05-30 17:16:24.958'),
('cmps8aosz000c97x5x26de2p2','cmpjybtj7003d1dk272xxxvos','cmps8aos5000497x5r015hlx7',4,'Bal çok lezzetli ve doğal olduğu belli. Tek eksiği kargo biraz geç geldi ama ürün harika. Bir sonraki siparişimi zaten oluşturdum.',true,'2026-05-29 10:49:17.074',NULL,NULL,NULL,NULL,NULL,'2026-05-30 17:16:24.958'),
